{
  "name": "テスト花子02",
  "talent": {
    "axis1": {
      "name": "傾聴力",
      "english": "Deep Listening",
      "description": "子どもの言葉の奥にある気持ちを丸ごと受け取る力",
      "items": ["子どもの話を聞く", "変化に気づく", "記録をつける"],
      "percentage": 40,
      "top5": ["子どもの話を聞く", "変化に気づく"]
    },
    "axis2": {
      "name": "関係構築",
      "english": "Connection Building",
      "description": "場を温め、人を巻き込みながら安心できる空間をつくる力",
      "items": ["場を和ませる", "巻き込む", "褒める"],
      "percentage": 35,
      "top5": ["場を和ませる"]
    },
    "axis3": {
      "name": "育成力",
      "english": "Nurturing Power",
      "description": "根気強く寄り添い続けることで、子どもの中に変化を生む力",
      "items": ["励ます", "根気強く教える", "絵を描く"],
      "percentage": 25,
      "top5": ["励ます", "根気強く教える"]
    }
  },
  "value": {
    "axis1": {
      "name": "誠実さ",
      "english": "Integrity",
      "description": "飾らず、正直に、相手に向き合い続けることを揺るぎない軸にする",
      "items": ["誠実", "正直", "素直さ"],
      "percentage": 40,
      "top5": ["誠実"]
    },
    "axis2": {
      "name": "成長志向",
      "english": "Growth Orientation",
      "description": "自分も相手も、今より少し先へ進めることに意味を見出す",
      "items": ["成長", "粘り強さ", "努力"],
      "percentage": 35,
      "top5": ["成長", "粘り強さ"]
    },
    "axis3": {
      "name": "公正な愛",
      "english": "Fair Compassion",
      "description": "誰一人取り残さず、同じ温かさで接することへのこだわり",
      "items": ["公平", "思いやり", "協調"],
      "percentage": 25,
      "top5": ["公平", "思いやり"]
    }
  },
  "passion": {
    "axis1": {
      "name": "子どもの教育",
      "english": "Children's Education",
      "description": "一人ひとりの子どもが育つ瞬間に立ち会うことへの深い引力",
      "items": ["教育", "子どもの成長", "学級づくり"],
      "percentage": 50,
      "top5": ["教育", "子どもの成長", "学級づくり"]
    },
    "axis2": {
      "name": "言葉と表現",
      "english": "Words & Expression",
      "description": "物語・歌・声を通じて、人の内側に届くものを手渡す喜び",
      "items": ["読み聞かせ", "合唱", "絵本"],
      "percentage": 35,
      "top5": ["読み聞かせ", "合唱"]
    },
    "axis3": {
      "name": "自然と創造",
      "english": "Nature & Creation",
      "description": "育てる・旅する・感じる、生活の中で心を整える営み",
      "items": ["ガーデニング", "旅行"],
      "percentage": 15,
      "top5": []
    }
  },
  "core_words": {
    "talent_core": "子どもの話を聞く",
    "value_core": "誠実",
    "passion_core": "子どもの成長"
  },
  "kakuchiiki": "誠実に子どもの話を聞いて、一人ひとりの成長を支える人",
  "kakuchiiki_options": [
    "子どもの変化を誠実に受け取って、学びの場を育てる人",
    "誠実に寄り添いながら、子どもの成長が連鎖する教育を広げる人",
    "子どもの声を丁寧に聞いて、成長の積み重なる場をつくる人"
  ],
  "insight": "あなたが「ちゃんと伝えきれたか」と心残りに感じるその感覚こそ、誰もが持てるわけではない才覚の証明だ。子どもの話を聞き、変化に気づき、根気強く寄り添う——それはスキルではなく、あなたの呼吸そのものだ。10年後、教え子たちがそれぞれの場所で誰かを支えているとしたら、その連鎖の起点にいるのはあなただ。「先生のおかげ」という言葉が広がっていくとき、あなたの誠実さと粘り強さが、目に見えない形で社会を編んでいる。",
  "what": {
    "products": [
      "学級の子ども一人ひとりへ、今週感じた変化を一言添えた個別メモを書く",
      "読み聞かせの場を定期的に設計し、絵本の選書と語りを自分の表現として磨く",
      "学校内でしんどさを抱えた子や若手教員の話を聞く「寄り添いの時間」を仕組みとしてつくる",
      "地域や学校を超えて、子どもや教師の声を集めるサークルや勉強会を立ち上げる",
      "全国を訪ね歩いて、しんどさを抱えた子と先生の隣にいる経験を記録として残し、教育の現場に届ける"
    ],
    "actions": "今日受け持った子どもの中で、一番気になった子の様子をノートに書き残す。その一行が、10年後の連鎖の最初の点になる。",
    "offer": "誠実に子どもの話を聞き、変化に気づき続けることで、「自分は大切にされた」と感じた子どもたちが、次の誰かを大切にする連鎖を社会に広げていく。"
  },
  "reward": {
    "economic": "教育支援・読み聞かせ・子育て相談など、あなたが自然にやっていることが、保護者・地域・学校法人からの依頼として積み重なっていく可能性がある。",
    "social": "数年後、教え子が「あの時先生が話を聞いてくれたから」と笑顔で話す瞬間、あなたはその子の人生のターニングポイントにいたことを知る。",
    "intrinsic": "気づいたら子どもの変化をメモしている。誰に頼まれなくても、しんどそうな顔をした子の隣に自然と座っている。それがあなたの呼吸だ。",
    "model": "誠実に寄り添い続けた時間が、子どもの成長という形で社会に残り、その連鎖が信頼と依頼を生み続けるモデルで生きていける。"
  }
}
